import socket
import threading
from collections import defaultdict

# Constants
HOST = '127.0.0.1'
PORT = 65432
MAX_PLAYERS = 100
UPDATE_INTERVAL = 0.1  # seconds

# Player data structure
Player = namedtuple('Player', ['id', 'position', 'direction'])

# Server state
players = defaultdict(Player)
clients = []

def handle_client(conn, addr):
    print(f"Connected by {addr}")
    while True:
        try:
            data = conn.recv(1024)
            if not data:
                break
            player_id = int(data.decode())
            players[player_id] = Player(player_id, (0, 0), (0, 0))  # Update position and direction as needed
            broadcast_state()
        except Exception as e:
            print(f"Error handling client {addr}: {e}")
            break
    conn.close()

def broadcast_state():
    state = {player.id: player for player in players.values()}
    for client_conn, _ in clients:
        try:
            client_conn.sendall(str(state).encode())
        except Exception as e:
            print(f"Error broadcasting to client: {e}")

def start_server():
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.bind((HOST, PORT))
        s.listen(MAX_PLAYERS)
        print(f"Server listening on {HOST}:{PORT}")
        while True:
            conn, addr = s.accept()
            clients.append((conn, addr))
            client_thread = threading.Thread(target=handle_client, args=(conn, addr))
            client_thread.start()

if __name__ == "__main__":
    server_thread = threading.Thread(target=start_server)
    server_thread.start()